import{_ as t,o as a,c as r,a7 as n}from"./chunks/framework.BgApuQ2e.js";const s="/images/clueyness-a-weird-kind-of-sad/Clueyness-1.png",o="/images/clueyness-a-weird-kind-of-sad/Screen-Shot-2016-05-30-at-3.07.05-PM.png",p="/images/clueyness-a-weird-kind-of-sad/pinit_fg_en_rect_gray_20.png",w=JSON.parse('{"title":"Clueyness: A Weird Kind of Sad","description":"","frontmatter":{"title":"Clueyness: A Weird Kind of Sad","titleZh":"迷茫感:一种奇特的忧伤","date":"2016-06-01T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2016/05/clueyness-a-weird-kind-of-sad.html","slug":"clueyness-a-weird-kind-of-sad"},"headers":[],"relativePath":"posts/clueyness-a-weird-kind-of-sad.md","filePath":"posts/clueyness-a-weird-kind-of-sad.md","lastUpdated":1782886257000}'),i={name:"posts/clueyness-a-weird-kind-of-sad.md"};function l(d,e,h,m,u,c){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="迷茫感-一种奇特的忧伤-·-clueyness-a-weird-kind-of-sad" tabindex="-1">迷茫感:一种奇特的忧伤 · Clueyness: A Weird Kind of Sad <a class="header-anchor" href="#迷茫感-一种奇特的忧伤-·-clueyness-a-weird-kind-of-sad" aria-label="Permalink to &quot;迷茫感:一种奇特的忧伤 · Clueyness: A Weird Kind of Sad&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2016/05/clueyness-a-weird-kind-of-sad.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2016/05/clueyness-a-weird-kind-of-sad.html</a> · 2016-06-01</p></blockquote><p>我要教你一个新词。<strong>Clue-y (克鲁忧)</strong>。听我解释。</p><p>我爸有次跟我讲了一个他年轻时的小故事,平平无奇。故事关于他父亲——我已故的爷爷——一个我认识的人里最快乐、最有爱的人之一。</p><p>某个周末,我爷爷去商店给家里带回来一个新的桌游:妙探寻凶 (Clue)。</p><p>他兴致勃勃地问我爸和我姑姑(当时一个 7 岁一个 9 岁)想不想玩。他们说想。于是他们围坐在厨房桌旁,爷爷打开游戏盒,读了说明,教他们怎么玩,分好卡牌,把每个部件都摆到位。</p><p>正当他们准备开始时,门铃响了。是邻居家的孩子,说他们正要出去玩一个大家平时经常玩的户外游戏。我爸和我姑姑想都没想,从座位上跳起来,跟着朋友们出门了。</p><p>几个小时后,他们回到家。游戏已经被收回柜子里了。</p><p>当时,我爸没多想——他们生活里再普通不过的一天。但后来,他总会想起那一天,而每次想起都觉得难受。他脑子里浮现出他父亲一个人坐在桌旁的样子,所有卡牌和部件都摆好了。他想象着他等了一会儿,慢慢接受今天玩不成了,然后把摆好的卡牌和部件一件件收起来,放回盒子,再把盒子放回柜子。</p><p>我爸跟我讲这个故事挺随机的吧?他会讲这个,是因为那次对话里我正试图描述一种我常有的感觉——就是会为某些处境下的某些人感到<em>极度</em>难过——尽管那个人可能根本没被那件事怎么影响到。这是一种很奇怪的、心碎般的强烈同情,给那些其实没经历什么特别糟糕的事的人。</p><p>我这么解释完,我爸说:&quot;我懂你说的。&quot;然后就讲了那个 Clue 的故事。太致命了。我爷爷本来<em>那么期待</em>玩游戏,他做爸爸做得<em>那么好、那么充满爱</em>,结果他<em>被辜负了、失望了</em>。他<em>一个人对着游戏板坐在那儿</em>,最后<em>把所有卡牌和部件都收回盒子里</em>,因为不行,游戏玩不成了,因为<em>他的孩子们宁愿去和朋友玩也不愿陪他</em>。</p><p>我爷爷打过二战。他可能失去过战友。他可能开枪打过人。他自己甚至可能中过枪,谁知道呢。但他一个人默默把 Clue 的部件一件件收回盒子的画面?这他妈就是不行。而现在,多亏了我爸分享这段记忆,我每天都被这个画面折磨着:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/05/Clueyness-1.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Stick figure putting Clue box back in the closet - clueyness"></a></p><p>不只是我爸对我这么干。你告诉我该怎么处理<a href="https://www.buzzfeed.com/stephaniemcneal/paw-paw-why?utm_term=.xfn5KdaKx#.piQP9aK9q" target="_blank" rel="noreferrer">这个该死的故事</a>,里面<em>那个爷爷给六个孙辈做了 12 个汉堡,结果只来了一个。</em></p><p>完全是 Clue 现场。而且这个故事里附了一张我这辈子见过最 cluey 的照片,没有之一。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/05/Screen-Shot-2016-05-30-at-3.07.05-PM.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt="papaw eating a hamburger alone"></a></p><p>读这故事的时候,我开始脑补这位天杀的好老头在杂货店里买齐所有食材,心情不错,满怀期待地等着晚上到来,然后回家一个一个手工捏出这 12 块肉饼——<em>说不定还精心琢磨着往里面加什么香料</em>——烤好面包,把所有事情的时间都掐得刚刚好。他甚至还做了<em>自制冰淇淋</em>。Cluey 到爆炸。你要是再脑补一下当晚的收场,更是没完没了。要么他就是把那 8 个没人吃的汉堡一个一个包起来放进冰箱,让自己以后每次热来吃的时候都被重新提醒一次这次被拒绝,要么——更惨——他直接<em>扔进了垃圾桶</em>。</p><p>读这个故事的时候唯一没让我当场自我了断的,是那个孙女——上帝保佑她——好歹是来了。因为你<em>想象一下</em>没来会怎样。</p><p>然后还有<a href="http://www.dailydot.com/lol/sad-papaw-ii-grandma-alone-art-show/" target="_blank" rel="noreferrer">这位 89 岁的奶奶</a>,她*<a href="https://twitter.com/Hablasian/status/728398280376258561/photo/1?ref_src=twsrc%5Etfw" target="_blank" rel="noreferrer">精心打扮</a>*,把自己的画作拿去参加一个画展。你猜怎么着?一!个!人!都!没!来!然后她把画收好开车回家,觉得自己「像个傻子」。你知道这叫什么吗?这就是 cluey 到骨子里。<em>尤其</em>是她偏偏用了「傻子」这个词。我真的不需要这种东西出现在我的生命里。</p><p>电影界对 clueyness 心知肚明,并且拿它当武器用。还记得《小鬼当家》里那个超级 cluey 的邻居老头吗?那个<em>那么善良、那么孤独、那么被误解</em>的老头?编剧根本就是凭空捏造出他来,先把 clueyness 这种情感负担砸给观众,然后在片尾让他和家人幸福团聚,再把这份负担一把卸下来。教科书级别的廉价套路。</p><p>傻愣愣的愧疚并不只发生在老人身上。大概五年前的一天,我心情糟透了,又赶时间,匆匆忙忙走出了公寓楼。一个联邦快递 (FedEx) 员工正站在楼门外,推着他那辆装满包裹的小车,想进楼把包裹放在公共信箱上面(我猜收件人不在家,他也没能按门铃让人放他进去)。我走出来时,他伸手想抓住我身后正在关上的门,但门在他抓到之前锁上了。门重新锁上后,他挫败地叹了口气,然后转向我问:「你能不能帮我开一下门,我把这些放进去?」但我已经走出十几步远了,还迟到了,所以我说了句「抱歉现在不行」,然后转身继续赶路。转身之前,我瞥见了他对我拒绝帮忙的反应。他脸上的表情像是一个善良的人被整个世界欺负了一整天。那张沮丧的脸的定格画面,那一整天越来越困扰我,而现在五年过去了,<em>我还在想这件事。</em></p><p>如果有人问我最后悔的事是什么,我只能撒谎,因为如果我回答「那个联邦快递员的事。我就是个禽兽」,那也太怪了吧。</p><p>傻愣愣的愧疚是个奇怪的现象。我外公可能在《妙探寻凶》事件发生一小时后就把它忘了。那个联邦快递员可能五分钟后就忘了我对他做的事。前几天我甚至对<em>一条狗</em>都产生了这种愧疚——它兴奋地想跟我玩,我很忙,用脚把它推开,它看着我<em>一脸困惑又受伤</em>,然后走到房间一角躺下了——而且狗根本不是真的存在的生物。我在这些事情上的心痛程度,和事情本身的悲剧性大概是 10000:1 的比例。</p><p>但知道这完全不理性,并不能让这种愧疚感稍微好受一点——每次我的整个夜晚都被「刚下 Uber 之后想起司机是个热情的人试图和我聊天但我没心情所以给了简短的回答直到他终于明白然后觉得尴尬闭嘴了」的内疚感毁掉时,我都会重新意识到这一点。</p><p>我大概注定就是要过一辈子对各种事情感到傻愣愣愧疚的人生了。但至少最近我看到一个小标题,让我稍微有点安慰:</p><h2 id="伤心爷爷不再伤心-数千人在他的烧烤聚会上排队等汉堡" tabindex="-1"><a href="http://abcnews.go.com/US/thousands-wait-line-burgers-papaws-cookout/story?id=37979163" target="_blank" rel="noreferrer">伤心爷爷不再伤心:数千人在他的烧烤聚会上排队等汉堡</a> <a class="header-anchor" href="#伤心爷爷不再伤心-数千人在他的烧烤聚会上排队等汉堡" aria-label="Permalink to &quot;[伤心爷爷不再伤心:数千人在他的烧烤聚会上排队等汉堡](http://abcnews.go.com/US/thousands-wait-line-burgers-papaws-cookout/story?id=37979163)&quot;">​</a></h2><p><strong>如果你现在正感到傻愣愣愧疚,这里还有三篇 Wait But Why 的文章可以让你感觉更糟:</strong></p><p><a href="https://waitbutwhy.com/2015/12/the-tail-end.html" target="_blank" rel="noreferrer"><strong>尾声</strong></a> —— 一次强烈的现实冲击</p><p><a href="https://waitbutwhy.com/2013/08/the-apple-game-how-good-person-are-you.html" target="_blank" rel="noreferrer"><strong>苹果游戏</strong></a> —— 你是个多好的人?</p><h2 id="兔子宣言-the-bunny-manifesto-——-如果这些内容对你来说有点太沉重了-这里有一些你绝对、绝对不需要为之感到-cluey-的生物" tabindex="-1"><a href="https://waitbutwhy.com/2013/08/the-bunny-manifesto.html" target="_blank" rel="noreferrer"><strong>兔子宣言 (The Bunny Manifesto)</strong></a> —— 如果这些内容对你来说有点太沉重了,这里有一些你绝对、绝对不需要为之感到 cluey 的生物 <a class="header-anchor" href="#兔子宣言-the-bunny-manifesto-——-如果这些内容对你来说有点太沉重了-这里有一些你绝对、绝对不需要为之感到-cluey-的生物" aria-label="Permalink to &quot;[**兔子宣言 (The Bunny Manifesto)**](https://waitbutwhy.com/2013/08/the-bunny-manifesto.html) —— 如果这些内容对你来说有点太沉重了,这里有一些你绝对、绝对不需要为之感到 cluey 的生物&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请注册我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会发给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2016/05/clueyness-a-weird-kind-of-sad.html&amp;description=Clueyness:%20A%20Weird%20Kind%20of%20Sad" target="_blank" rel="noreferrer"><img src="'+p+'" alt=""></a></p>',34)])])}const y=t(i,[["render",l]]);export{w as __pageData,y as default};
